// Probe: server filter chips, nav rail labels, settings interactions
import {
  APP_URL,
  clickSemantic as clickTxt,
  enableFlutterAccessibility as acc,
  openProbePage,
} from '../support/probe_runtime.mjs';

const { browser, page } = await openProbePage();

await page.goto(APP_URL, { waitUntil: 'load', timeout: 20000 });
await page.waitForTimeout(2000); await acc(page);

// 1. Probe ALL semantics elements with their role and position
console.log('=== COMPLETE SEMANTICS TREE ===');
const all = await page.evaluate(() => {
  const sems = document.querySelectorAll('flt-semantics');
  const items = [];
  for (const s of sems) {
    const r = s.getBoundingClientRect();
    if (r.width > 0) {
      const role = s.getAttribute('role')||'';
      const label = s.getAttribute('aria-label')||'';
      const text = (s.textContent||'').trim().substring(0,50);
      const tag = s.tagName;
      items.push({role, label, text, x:Math.round(r.x), y:Math.round(r.y), w:Math.round(r.width)});
    }
  }
  return items;
});
// Show role, text, and position for all items
for (const i of all) {
  if (i.role || i.label || i.text) {
    console.log(`  [${i.role||'-'}] label="${i.label}" text="${i.text}" at ${i.x},${i.y} ${i.w}px`);
  }
}

// 2. Check for nav rail labels (Chats, Servers, Agents, Memory, Config, Settings)
console.log('\n=== NAV RAIL SEARCH ===');
const navLabels = ['Chats','Servers','Agents','Memory','Config','Settings'];
for (const l of navLabels) {
  const found = all.filter(i => i.text.includes(l) || i.label.includes(l));
  if (found.length > 0) {
    for (const f of found) console.log(`  Found "${l}": [${f.role}] "${f.text}" at ${f.x},${f.y}`);
  } else {
    console.log(`  NOT FOUND: "${l}"`);
  }
}

// 3. Check for server filter labels
console.log('\n=== SERVER FILTER SEARCH ===');
const filterLabels = ['All','Local Gormes','Office Gormes'];
for (const l of filterLabels) {
  const found = all.filter(i => i.text.includes(l) || i.label.includes(l));
  if (found.length > 0) {
    for (const f of found) console.log(`  Found "${l}": [${f.role}] "${f.text}" at ${f.x},${f.y}`);
  } else {
    console.log(`  NOT FOUND: "${l}"`);
  }
}

// 4. Check for settings screen interactions
await page.goto(`${APP_URL}#/settings`, { waitUntil: 'load', timeout: 15000 });
await page.waitForTimeout(1500); await acc(page);

const settings = await page.evaluate(() => {
  const btns = document.querySelectorAll('flt-semantics[role="button"]');
  return Array.from(btns).filter(b => b.getBoundingClientRect().width > 0).map(b => ({
    text: (b.textContent||'').trim().substring(0,40),
    label: b.getAttribute('aria-label')||'',
    x: Math.round(b.getBoundingClientRect().x), y: Math.round(b.getBoundingClientRect().y),
  }));
});
console.log('\n=== SETTINGS BUTTONS ===');
for (const b of settings) console.log(`  "${b.label||b.text}" at ${b.x},${b.y}`);

await browser.close();

// Probe remaining features: gateway manage modal, mobile shell, voice toggles, command word, route guard
import {
  APP_URL,
  clickSemantic as click,
  enableFlutterAccessibility as a11y,
  openProbePage,
} from '../support/probe_runtime.mjs';

const { browser, page } = await openProbePage();

// 1. MOBILE VIEWPORT
console.log('=== 1. MOBILE VIEWPORT (390x844) ===');
await page.setViewportSize({ width: 390, height: 844 });
await page.goto(APP_URL, { timeout: 20000 });
await page.waitForTimeout(2000); await a11y(page);

const mobileLayout = await page.evaluate(() => {
  const sems = document.querySelectorAll('flt-semantics');
  const items = [];
  for (const s of sems) {
    const r = s.getBoundingClientRect();
    const role = s.getAttribute('role')||'';
    const t = (s.textContent||'').trim().substring(0,30);
    if (r.width > 0 && (role || t)) items.push({role, text:t, x:Math.round(r.x), y:Math.round(r.y), w:Math.round(r.width), h:Math.round(r.height)});
  }
  return items.slice(0,30);
});
console.log('Mobile semantics:');
for (const m of mobileLayout) {
  if (m.text || m.role) console.log(`  [${m.role}] "${m.text}" at ${m.x},${m.y} ${m.w}x${m.h}`);
}
await page.screenshot({path:'/tmp/navivox-mobile.png'});

// 2. GATEWAY MANAGEMENT MODAL
console.log('\n=== 2. GATEWAY MANAGE MODAL ===');
await page.setViewportSize({ width: 1280, height: 900 });
await page.goto(`${APP_URL}#/servers`, { timeout: 15000 });
await page.waitForTimeout(1500); await a11y(page);

// Click Manage for Local Gormes
await click(page, 'Manage Local Gormes');
await page.waitForTimeout(2000);

const gwDetail = await page.evaluate(() => {
  const sems = document.querySelectorAll('flt-semantics');
  const texts = new Set();
  for (const s of sems) {
    const t = (s.textContent||'').trim();
    if (t && !t.startsWith('Gateways') && !t.startsWith('N\n')) {
      for (const line of t.split('\n')) {
        const l = line.trim();
        if (l) texts.add(l.substring(0,80));
      }
    }
  }
  return Array.from(texts).filter(t => t.length > 5).slice(0,20);
});
console.log('Gateway detail texts:');
for (const t of gwDetail) console.log(`  "${t}"`);

// Dismiss
await page.keyboard.press('Escape');
await page.waitForTimeout(1000);

// 3. SETTINGS TOGGLES (continuous voice switch)
console.log('\n=== 3. VOICE SETTINGS TOGGLES ===');
await page.goto(`${APP_URL}#/settings`, { timeout: 15000 });
await page.waitForTimeout(1500); await a11y(page);

const switches = await page.evaluate(() => {
  const switches = document.querySelectorAll('flt-semantics[role="switch"], [role="checkbox"]');
  return Array.from(switches).filter(s => s.getBoundingClientRect().width > 0).map(s => ({
    role: s.getAttribute('role'),
    label: s.getAttribute('aria-label')||'',
    checked: s.getAttribute('aria-checked'),
    text: (s.textContent||'').trim().substring(0,40),
    rect: s.getBoundingClientRect(),
  }));
});
console.log('Switch elements:');
for (const s of switches) console.log(`  [${s.role}] label="${s.label}" checked=${s.checked} text="${s.text}"`);

// 4. APP SHELL NAVIGATION - check all screens for nav bar structure
console.log('\n=== 4. NAVIGATION STRUCTURE ===');
const routes = ['/chats', '/servers', '/agents', '/memory', '/config', '/settings'];
const navText = {};
for (const route of routes) {
  await page.goto(`${APP_URL}#${route}`, { timeout: 15000 }).catch(()=>{});
  await page.waitForTimeout(1500); await a11y(page);

  // Look for bottom nav items (mobile) or navigation rail items
  const items = await page.evaluate(() => {
    const sems = document.querySelectorAll('flt-semantics');
    const nav = [];
    for (const s of sems) {
      const r = s.getBoundingClientRect();
      const role = s.getAttribute('role')||'';
      const t = (s.textContent||'').trim().substring(0,30);
      // Bottom nav items are typically at the bottom of the screen
      if (r.width > 0 && r.y > 600 && (role === 'button' || role === '')) {
        nav.push({role, text:t, x:Math.round(r.x), y:Math.round(r.y), w:Math.round(r.width)});
      }
    }
    return nav.slice(0,10);
  });
  navText[route] = items;
  console.log(`${route} bottom buttons:`, items.length);
  for (const i of items) console.log(`  [${i.role}] "${i.text}" at y=${i.y}`);
}

await browser.close();

// Probe remaining testable features: agents select, search, voice toggles, register gateway
import {
  APP_URL,
  clickSemantic as click,
  enableFlutterAccessibility as a11y,
  openProbePage,
} from '../support/probe_runtime.mjs';

const { browser, page } = await openProbePage();

// 1. AGENTS - profile selection
console.log('=== 1. AGENTS: profile selection ===');
await page.goto(`${APP_URL}#/agents`, {timeout:15000});
await page.waitForTimeout(1500); await a11y(page);

// Click Voice Agent profile
await click(page, 'Voice Agent'); await page.waitForTimeout(2000);

const agentsAfter = await page.evaluate(() => {
  const sems = document.querySelectorAll('flt-semantics');
  const t = new Set();
  for (const s of sems) {
    const txt = (s.textContent||'').trim();
    if (txt && (txt.includes('Active profile') || txt.includes('Voice Agent') || txt.includes('voice'))) {
      t.add(txt.substring(0,60));
    }
  }
  return [...t];
});
console.log('After Voice Agent click:');
for (const a of agentsAfter) console.log('  "'+a+'"');

// 2. SEARCH - type text in search field
console.log('\n=== 2. SEARCH field ===');
await page.goto(APP_URL, {timeout:15000});
await page.waitForTimeout(1500); await a11y(page);

// The search input has aria-label "Search profiles" - it's a disabled input
// Try clicking the semantics overlay
const searchInfo = await page.evaluate(() => {
  const input = document.querySelector('input[aria-label="Search profiles"]');
  if (!input) return {found: false};
  const rect = input.getBoundingClientRect();
  const parent = input.closest('flt-semantics');
  return {found: true, disabled: input.disabled, rect: {x:Math.round(rect.x), y:Math.round(rect.y)}, parentRect: parent ? {x:Math.round(parent.getBoundingClientRect().x), y:Math.round(parent.getBoundingClientRect().y)} : null};
});
console.log('Search input:', JSON.stringify(searchInfo));

if (searchInfo.found) {
  // Click search button to activate search mode
  await click(page, 'Search profiles');
  await page.waitForTimeout(1500);

  // Now search field should be active
  // Check for input field at the top
  const searchActive = await page.evaluate(() => {
    const inputs = document.querySelectorAll('input');
    return Array.from(inputs).filter(i => i.getBoundingClientRect().width > 0).map(i => ({
      label: i.getAttribute('aria-label'),
      disabled: i.disabled,
      rect: {x:Math.round(i.getBoundingClientRect().x), y:Math.round(i.getBoundingClientRect().y)}
    }));
  });
  console.log('Active inputs:', JSON.stringify(searchActive));

  // Try typing in the search
  // Click on the search semantics
  await page.evaluate(() => {
    const sems = document.querySelectorAll('flt-semantics');
    for (const s of sems) {
      if ((s.textContent||'').includes('Search profiles') && s.getAttribute('role') === 'button') {
        s.dispatchEvent(new PointerEvent('pointerdown',{bubbles:true}));
        s.dispatchEvent(new PointerEvent('pointerup',{bubbles:true}));
        s.dispatchEvent(new MouseEvent('click',{bubbles:true}));
        return;
      }
    }
  });
  await page.waitForTimeout(1000);

  await page.keyboard.type('mineru');
  await page.waitForTimeout(1000);

  const afterSearch = await page.evaluate(() => {
    const sems = document.querySelectorAll('flt-semantics');
    const t = new Set();
    for (const s of sems) {
      const txt = (s.textContent||'').trim();
      if (txt) t.add(txt.substring(0,40));
    }
    return [...t].filter(x => x.includes('Mineru') || x.includes('Support') || x.includes('Voice')).slice(0,5);
  });
  console.log('After search "mineru":', JSON.stringify(afterSearch));
}

// 3. VOICE TOGGLES - check switch state
console.log('\n=== 3. SETTINGS: switches ===');
await page.goto(`${APP_URL}#/settings`, {timeout:15000});
await page.waitForTimeout(1500); await a11y(page);

const toggles = await page.evaluate(() => {
  const all = document.querySelectorAll('[role="switch"], [aria-checked], .SwitchListTile');
  const results = [];
  for (const el of all) {
    const r = el.getBoundingClientRect();
    if (r.width > 0) {
      results.push({
        tag: el.tagName,
        role: el.getAttribute('role'),
        checked: el.getAttribute('aria-checked'),
        label: el.getAttribute('aria-label')||'',
        text: (el.textContent||'').trim().substring(0,40),
        y: Math.round(r.y)
      });
    }
  }
  return results;
});
console.log('Toggle/switch elements:', toggles.length);
for (const t of toggles) {
  console.log('  ['+t.role+'] checked='+t.checked+' label="'+t.label+'" text="'+t.text+'" at y='+t.y);
}

// 4. REGISTER GATEWAY - check if clickable
console.log('\n=== 4. REGISTER GATEWAY ===');
await page.goto(`${APP_URL}#/servers`, {timeout:15000});
await page.waitForTimeout(1500); await a11y(page);

await click(page, 'Register gateway');
await page.waitForTimeout(2000);
console.log('URL after register:', page.url());

// 5. MOBILE TAB CLICK - try clicking a tab
console.log('\n=== 5. MOBILE TAB CLICK ===');
await page.setViewportSize({width:390,height:844});
await page.goto(APP_URL, {timeout:15000});
await page.waitForTimeout(1500); await a11y(page);

// Click the Memory tab (3rd tab)
await click(page, 'tab');
await page.waitForTimeout(2000);
console.log('URL after 2nd tab click:', page.url());

// Also try clicking with tablist click at specific tab position
const tabs = await page.evaluate(() => {
  const ts = document.querySelectorAll('flt-semantics[role="tab"]');
  return Array.from(ts).map((t,i) => {
    const r = t.getBoundingClientRect();
    return {index: i, x:Math.round(r.x), y:Math.round(r.y), w:Math.round(r.width)};
  });
});
console.log('Tabs:', JSON.stringify(tabs));

if (tabs.length >= 3) {
  // Click the 3rd tab (Memory - index 2)
  await page.mouse.click(tabs[2].x + tabs[2].w/2, tabs[2].y + 20);
  await page.waitForTimeout(2000);
  console.log('URL after tab 2 click:', page.url());
}

await page.screenshot({path:'/tmp/navivox-remaining.png'});
await browser.close();

// Probe all testable but untested features
import {
  APP_URL as APP,
  createProbeBrowser,
  createProbePage,
  enableFlutterAccessibility,
} from '../support/probe_runtime.mjs';

const b = await createProbeBrowser({ launchOptions: { args: ['--no-sandbox'] } });

async function probe(label, url, fn) {
  const p = await createProbePage(b);
  await p.goto(url, { timeout: 15000 });
  await p.waitForTimeout(2000);
  await enableFlutterAccessibility(p);
  const result = await fn(p);
  console.log(`\n=== ${label} ===`);
  if (Array.isArray(result)) {
    result.forEach((r, i) => console.log(`  ${i}: ${JSON.stringify(r)}`));
  } else {
    console.log(`  ${JSON.stringify(result)}`);
  }
  await p.close();
}

// 1. Settings screen - command word sheet voice toggles
await probe('Settings switches', APP + '#/settings', async (p) => {
  const labels = await p.evaluate(() => {
    return Array.from(document.querySelectorAll('[role="switch"]'))
      .map(e => ({
        label: e.getAttribute('aria-label') || '',
        checked: e.getAttribute('aria-checked'),
        text: (e.textContent || '').trim().substring(0, 40),
      }));
  });
  return labels.length > 0 ? labels : 'NO SWITCHES FOUND';
});

// 2. Chat screen - more_vert info sheet, voice banner
await probe('Chat thread semantics', APP, async (p) => {
  // Click Support Triage to enter chat
  const btns = await p.evaluate(() => {
    const s = document.querySelectorAll('flt-semantics[role="button"]');
    for (const e of s) {
      if ((e.textContent || '').includes('Support Triage')) {
        const r = e.getBoundingClientRect();
        return { x: r.x + r.width / 2, y: r.y + r.height / 2 };
      }
    }
    return null;
  });
  if (btns) {
    await p.mouse.click(btns.x, btns.y);
    await p.waitForTimeout(2000);
  }
  const text = await p.evaluate(() => {
    const s = document.querySelectorAll('flt-semantics');
    return Array.from(s)
      .map(e => ({
        role: e.getAttribute('role') || '',
        text: (e.textContent || '').trim().substring(0, 50),
        label: e.getAttribute('aria-label') || '',
      }))
      .filter(e => e.text.length > 0)
      .slice(0, 30);
  });
  return text;
});

// 3. FAB → Create from seed
await probe('FAB create from seed', APP, async (p) => {
  const btns = await p.evaluate(() => {
    const s = document.querySelectorAll('flt-semantics[role="button"]');
    for (const e of s) {
      if ((e.textContent || '').includes('Add profile')) {
        const r = e.getBoundingClientRect();
        return { x: r.x + r.width / 2, y: r.y + r.height / 2 };
      }
    }
    return null;
  });
  if (btns) {
    await p.mouse.click(btns.x, btns.y);
    await p.waitForTimeout(2000);
  }
  const text = await p.evaluate(() => {
    const s = document.querySelectorAll('flt-semantics');
    return Array.from(s)
      .map(e => (e.textContent || '').trim().substring(0, 60))
      .filter(t => t.includes('Create from') || t.includes('New profile') || t.includes('Add server'));
  });
  return text;
});

// 4. Config screen - edit button
await probe('Config screen', APP + '#/config', async (p) => {
  const btns = await p.evaluate(() => {
    const s = document.querySelectorAll('flt-semantics[role="button"]');
    return Array.from(s).map(e => ({
      text: (e.textContent || '').trim().substring(0, 50),
      label: e.getAttribute('aria-label') || '',
    }));
  });
  return btns;
});

await b.close();

// Probe untested features: desktop nav rail, gateway detail, profile detail, FAB, filter, search
import {
  APP_URL,
  clickSemantic as clickTxt,
  enableFlutterAccessibility as acc,
  openProbePage,
} from '../support/probe_runtime.mjs';

const { browser, page } = await openProbePage();

// 1. Check if desktop nav rail exists (all destinations)
await page.goto(APP_URL, { waitUntil: 'load', timeout: 20000 });
await page.waitForTimeout(2000); await acc(page);
console.log('=== DESKTOP NAV RAIL ===');
const rail = await page.evaluate(() => {
  // Desktop NavigationRail renders flt-semantics with NavigationRailDestination labels
  const sems = document.querySelectorAll('flt-semantics');
  const items = [];
  for (const s of sems) {
    const t = (s.textContent||'').trim();
    const r = s.getAttribute('role')||'';
    const rect = s.getBoundingClientRect();
    if (rect.width > 0 && rect.height > 0 && (r === 'button' || (t && rect.x < 257))) {
      items.push({role:r, text:t.substring(0,40), x:Math.round(rect.x), y:Math.round(rect.y)});
    }
  }
  return items;
});
for (const i of rail) console.log(`  [${i.role}] "${i.text}" at ${i.x},${i.y}`);

// 2. Check FAB → Add profile bottom sheet
await clickTxt(page, 'Add profile');
await page.waitForTimeout(2000);
const fabSheet = await page.evaluate(() => {
  const sems = document.querySelectorAll('flt-semantics');
  const items = [];
  for (const s of sems) {
    const t = (s.textContent||'').trim();
    const rect = s.getBoundingClientRect();
    if (rect.width > 0 && t && !t.startsWith('Navivox') && !t.startsWith('N\n')) {
      items.push(t.substring(0,80));
    }
  }
  return [...new Set(items)].slice(0,15);
});
console.log('\n=== FAB Bottom Sheet ===');
for (const i of fabSheet) console.log(`  "${i}"`);

// Dismiss FAB sheet
await page.keyboard.press('Escape');
await page.waitForTimeout(1000);

// 3. Check long-press profile detail (Support Triage)
console.log('\n=== PROFILE DETAIL (long press support) ===');
await clickTxt(page, 'Support Triage');
await page.waitForTimeout(2000);
// Actually long press on the Support Triage tile
// The click above navigated to chat, so go back
await page.goBack();
await page.waitForTimeout(2000); await acc(page);

// Try to trigger long-press via sequential pointer events
await page.evaluate(() => {
  const btns = document.querySelectorAll('flt-semantics[role="button"]');
  for (const b of btns) {
    if ((b.textContent||'').includes('Support Triage')) {
      // Try gesture sequence for long press
      const rect = b.getBoundingClientRect();
